    )
}

pub(crate) fn host_cli_system_runtime_surface(entry: &serde_yaml::Value, _system: &str) -> String {
    yaml_string(yaml_lookup(entry, &["runtime_root"])).unwrap_or_default()
}

pub(crate) fn host_cli_system_materialization_mode(
